function cleanupExpiredDownloadTokens(): void {
  const now = Date.now();
  for (const [token, value] of downloadTokenToJob.entries()) {
    if (value.expiresAtMs <= now) {
      downloadTokenToJob.delete(token);
      const job = exportJobs.get(value.jobId);
      if (job) {
        job.downloadToken = undefined;
      }
    }
  }
}

function buildDownloadUrl(baseUrl: string, token: string): string {
  return `${sanitizeBaseUrl(baseUrl)}/api/v1/exports/download/${token}`;
}

export async function createExcelExportJob(params: CreateExportJobParams): Promise<{ job: ExcelExportJob; downloadUrl: string }> {
  assertTenantAccess(params.userId, params.tenantId);

  const scope = normalizeExportScope(params.request.scope);
  const locations = normalizeExportLocations(params.request.locations);
  const now = nowIso();
  const jobId = createId();
  const fileName = `joyus-fast-casual-export-${params.tenantId}-${jobId}.xlsx`;
  const outputDir = path.join(exportRootDir(), params.tenantId);
  const outputPath = path.join(outputDir, fileName);

  const initialJob: ExcelExportJob = {
    id: jobId,
    userId: params.userId,
    tenantId: params.tenantId,
    status: 'pending',
    scope,
    locations,
    dateStart: params.request.date_start,
    dateEnd: params.request.date_end,
    scenarioId: params.request.scenario_id,
    filePath: outputPath,
    fileName,
    createdAt: now,
    updatedAt: now,
  };
  exportJobs.set(jobId, initialJob);

  try {
    await mkdir(outputDir, { recursive: true });
    const workbook = isWorkbookPayload(params.request.workbook_data)
      ? params.request.workbook_data
      : defaultWorkbookPayload(params.tenantId, params.userId, scope, locations, params.request);

    await buildWorkbookFile({
      outputPath,
      workbook,
    });

    const fileStats = await stat(outputPath);
    const token = randomBytes(24).toString('hex');
    const expiresAtMs = Date.now() + signedUrlTtlSeconds() * 1000;
    const expiresAtIso = new Date(expiresAtMs).toISOString();
    const downloadUrl = buildDownloadUrl(params.baseUrl, token);

    downloadTokenToJob.set(token, { jobId, expiresAtMs });
    exportJobs.set(jobId, {
      ...initialJob,
      status: 'completed',
      fileSizeBytes: fileStats.size,
      downloadToken: token,
      downloadExpiresAt: expiresAtIso,
      updatedAt: nowIso(),
    });

    const completedJob = exportJobs.get(jobId);
    if (!completedJob) {
      throw new Error('Export job was not persisted.');
    }

    return { job: completedJob, downloadUrl };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    exportJobs.set(jobId, {
      ...initialJob,
      status: 'failed',
      error: message,
      updatedAt: nowIso(),
    });
    throw error;
  }
}

export function getExcelExportJobForUser(userId: string, tenantId: string, exportId: string): ExcelExportJob | null {
  assertTenantAccess(userId, tenantId);
  const job = exportJobs.get(exportId);
  if (!job) return null;
  if (job.userId !== userId || job.tenantId !== tenantId) return null;
  return job;
}

export function resolveDownloadToken(token: string): { job: ExcelExportJob; filePath: string } | null {
  cleanupExpiredDownloadTokens();

  const tokenRecord = downloadTokenToJob.get(token);
  if (!tokenRecord) return null;

  const job = exportJobs.get(tokenRecord.jobId);
  if (!job || !job.filePath || job.status !== 'completed') return null;
  return { job, filePath: job.filePath };
}

import { Router, Request, Response, NextFunction } from 'express';

import { getUserFromToken } from '../auth/verify.js';
import { db, auditLogs } from '../db/client.js';

import { createExcelExportJob, getExcelExportJobForUser, resolveDownloadToken } from './service.js';
import { ExcelExportRequest } from './types.js';

interface AuthenticatedRequest extends Request {
  authUser?: {
    id: string;
    email: string;
    name: string | null;
  };
}

function extractBearerToken(req: Request): string | null {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) return null;
  return authHeader.substring(7);
}

function inferredBaseUrl(req: Request): string {
  return process.env.BASE_URL || `${req.protocol}://${req.get('host')}`;
}

async function writeAudit(
  userId: string,
  tool: string,
  input: Record<string, unknown>,
  success: boolean,
  duration: number,
  error?: string
): Promise<void> {
  try {
    await db.insert(auditLogs).values({
      userId,
      tool,
      input,
      success,
      duration,
      error,
    });
  } catch (auditError) {
    console.warn('Failed to persist export audit log', auditError);
  }
}

async function requireTokenAuth(req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> {
  const token = extractBearerToken(req);
  if (!token) {
    res.status(401).json({ error: 'Missing or invalid authorization header' });
    return;
  }

  const user = await getUserFromToken(token);
  if (!user) {
    res.status(401).json({ error: 'Invalid token' });
    return;
  }

  req.authUser = {
    id: user.id,
    email: user.email,
    name: user.name,
  };
  next();
}

export const exportRouter = Router();

exportRouter.post('/tenants/:tenantId/exports/excel', requireTokenAuth, async (req: AuthenticatedRequest, res: Response) => {
  const startedAt = Date.now();
  const user = req.authUser;
  const tenantId = req.params.tenantId;

  if (!user) {
    res.status(401).json({ error: 'Unauthorized' });
    return;
  }

  const body = (req.body && typeof req.body === 'object' ? req.body : {}) as ExcelExportRequest;

  try {
    const { job, downloadUrl } = await createExcelExportJob({
      userId: user.id,
      tenantId,
      request: body,
      baseUrl: inferredBaseUrl(req),
    });

    await writeAudit(
      user.id,
      'ops_export_excel_api_create',
      {
        tenant_id: tenantId,
        scope: body.scope || 'current_view',
        locations: body.locations || 'current',
        scenario_id: body.scenario_id || null,
      },
      true,
      Date.now() - startedAt
    );

    res.status(201).json({
      export_id: job.id,
      tenant_id: job.tenantId,
      status: job.status,
      scope: job.scope,
      locations: job.locations,
      created_at: job.createdAt,
      updated_at: job.updatedAt,
      download_url: downloadUrl,
      expires_at: job.downloadExpiresAt,
      file_name: job.fileName,
      file_size_bytes: job.fileSizeBytes,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Export generation failed';

    await writeAudit(
      user.id,
      'ops_export_excel_api_create',
      {
        tenant_id: tenantId,
        scope: body.scope || 'current_view',
        locations: body.locations || 'current',
        scenario_id: body.scenario_id || null,
      },
      false,
      Date.now() - startedAt,
      message
    );

    if (message.includes('not authorized')) {
      res.status(403).json({ error: message });
      return;
    }
    res.status(500).json({ error: message });
  }
});

exportRouter.get('/tenants/:tenantId/exports/:exportId', requireTokenAuth, async (req: AuthenticatedRequest, res: Response) => {
  const user = req.authUser;
  const { tenantId, exportId } = req.params;

  if (!user) {
    res.status(401).json({ error: 'Unauthorized' });
    return;
  }

  try {
    const job = getExcelExportJobForUser(user.id, tenantId, exportId);
    if (!job) {
      res.status(404).json({ error: 'Export not found' });
      return;
    }

    res.json({
      export_id: job.id,
      tenant_id: job.tenantId,
      status: job.status,
      scope: job.scope,
      locations: job.locations,
      created_at: job.createdAt,
      updated_at: job.updatedAt,
      expires_at: job.downloadExpiresAt,
      file_name: job.fileName,
      file_size_bytes: job.fileSizeBytes,
      error: job.error,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unable to fetch export';
    if (message.includes('not authorized')) {
      res.status(403).json({ error: message });
      return;
    }
    res.status(500).json({ error: message });
  }
});

exportRouter.get('/exports/download/:token', async (req: Request, res: Response) => {
  const token = req.params.token;
  const resolved = resolveDownloadToken(token);

  if (!resolved) {
    res.status(404).json({ error: 'Download link is invalid or expired' });
    return;
  }

  const { job, filePath } = resolved;
  const fileName = job.fileName || `${job.id}.xlsx`;
  res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
  res.download(filePath, fileName);
});

